import &#123; Component, ContentChild, Input, TemplateRef &#125; from &quot;@angular&#x2F;core&quot;;@Component(&#123;    selector:&#39;app-partner-carousel&#39;,    template:&#96;    &lt;div class&#x3D;&quot;carousel&quot;&gt;    &lt;div class&#x3D;&quot;btn-pre&quot; (click)&#x3D;&quot;carouselMove(&#39;LEFT&#39;)&quot; [hidden]&#x3D;&quot;carouselIndex&#x3D;&#x3D;&#x3D;0&quot;&gt;&lt;&#x2F;div&gt;    &lt;div class&#x3D;&quot;slick-window&quot;&gt;        &lt;div class&#x3D;&quot;slick-container&quot; *ngIf&#x3D;&quot;data.length&gt;0&quot; [ngStyle]&#x3D;&quot;carouselAnimotion&quot;&gt;          &lt;span *ngFor&#x3D;&quot;let dataItem of data&quot;&gt;            &lt;ng-container            *ngIf&#x3D;&quot;dataItemTemplateRef&quot;            [ngTemplateOutlet]&#x3D;&quot;dataItemTemplateRef&quot;            [ngTemplateOutletContext]&#x3D;&quot;&#123;$implicit:dataItem&#125;&quot;&gt;&lt;&#x2F;ng-container&gt;          &lt;&#x2F;span&gt;        &lt;&#x2F;div&gt;    &lt;&#x2F;div&gt;    &lt;div class&#x3D;&quot;btn-next&quot; (click)&#x3D;&quot;carouselMove(&#39;RIGHT&#39;)&quot; [hidden]&#x3D;&quot;carouselIndex&gt;&#x3D;data.length-3&quot;&gt;&lt;&#x2F;div&gt;    &lt;&#x2F;div&gt;    &#96;,    styles:[&#96;.carousel&#123;display:flex&#125;&#96;,    &#96;.slick-window &#123;      position: relative;      width: 690px;      overflow: hidden;      transform: translateZ(0);    &#125;&#96;,    &#96;.slick-container&#123;      transform: translate3d(0px, 0px, 0px);      transition: 0.6s ease-in-out;      &#x2F;&#x2F; width: 1500px;      position: relative;      line-height: inherit;      margin-right: 45px;      overflow-y: hidden;    &#125;&#96;,    &#96;.slick-container&gt;span&#123;display:inline-block&#125;&#96;,    &#96;.btn-pre, .btn-next &#123;      &#x2F;&#x2F; width: 15px;      cursor: pointer;   &#125;&#96;,   &#96;.btn-pre::before, .btn-next::before &#123;      content: &#39;&#39;;      width: 0;      height: 0;      position: absolute;      top: 16px;      border-top: 22px solid transparent;      border-bottom: 22px solid transparent;   &#125;&#96;,   &#96;.btn-pre::before &#123;      border-right: 15px solid #ccc;      border-left: 0px solid transparent;      left: -15px;   &#125;&#96;,   &#96;.btn-next::before &#123;      border-right: 0px solid transparent;      border-left: 15px solid #ccc;   &#125;&#96;]&#125;)export class PartnerCarouselComponent&#123;  readonly slickWidth &#x3D; 230;  carouselAnimotion:any &#x3D; &#123;&#125;;  private _data:Array&lt;any&gt; &#x3D; [];  @Input()     set data(value:Array&lt;any&gt;)&#123;      this.carouselAnimotion.width &#x3D; &#96;$&#123;this.slickWidth * value.length&#125;px&#96;;      this._data &#x3D; value;    &#125;    get data()&#123;      return this._data;    &#125;    @ContentChild(&#39;dataItem&#39;, &#123;static:false&#125;) dataItemTemplateRef:TemplateRef&lt;any&gt;;    carouselIndex:number &#x3D; 0;    constructor()&#123;&#125;    carouselMove(orient: string) &#123;        let distance &#x3D; 0;        if (orient &#x3D;&#x3D;&#x3D; &#39;LEFT&#39;) &#123;          this.carouselIndex &#x3D; this.carouselIndex &gt; 3 ? this.carouselIndex -&#x3D; 3 : 0        &#125;        if (orient &#x3D;&#x3D;&#x3D; &#39;RIGHT&#39;) &#123;          this.carouselIndex &#x3D; this.carouselIndex &lt; this._data.length - 5 ? this.carouselIndex +&#x3D; 3 : this._data.length - 3;        &#125;        distance &#x3D; this.slickWidth * this.carouselIndex;        this.carouselAnimotion.transform &#x3D; &#96;translate3d(-$&#123;distance&#125;px, 0px, 0px)&#96;;    &#125;&#125;
滑动原理position: relative和transform: translateZ(0)将‘窗口’定位，其子元素是宽度超过屏幕宽度的所有滑块的集合，这个超长的‘胶片’用translate3d控制移动，使其某一格可以暴露在窗口中移动的动画效果为 transition: 0.6s ease-in-out
循环体套用父元素模板子组件(Carousel)中，为每个item套用其宿主定义的template，这里用到了NgContainer和TemplateRef，NgContainer使组件可以内嵌视图模板，内嵌的内容（ng-template）用ViewChild读取，此处声明为dataItemTemplateRef，使用NgTemplateOutlet指令将dataItemTemplateRef插入到ng-content位置，同时可以用ngTemplateOutletContext指令为内嵌视图附加一个上下文对象，显然就是为传递循环体的item打造的。使用#id指定要插入到ng-container的template官方示例:&lt;ng-container *ngTemplateOutlet&#x3D;&quot;greet&quot;&gt;&lt;&#x2F;ng-container&gt;&lt;hr&gt;&lt;ng-container *ngTemplateOutlet&#x3D;&quot;eng; context: myContext&quot;&gt;&lt;&#x2F;ng-container&gt;&lt;hr&gt;&lt;ng-container *ngTemplateOutlet&#x3D;&quot;svk; context: myContext&quot;&gt;&lt;&#x2F;ng-container&gt;&lt;hr&gt;&lt;ng-template #greet&gt;&lt;span&gt;Hello&lt;&#x2F;span&gt;&lt;&#x2F;ng-template&gt;&lt;ng-template #eng let-name&gt;&lt;span&gt;Hello &#123;&#123;name&#125;&#125;!&lt;&#x2F;span&gt;&lt;&#x2F;ng-template&gt;&lt;ng-template #svk let-person&#x3D;&quot;localSk&quot;&gt;&lt;span&gt;Ahoj &#123;&#123;person&#125;&#125;!&lt;&#x2F;span&gt;&lt;&#x2F;ng-template&gt;其中 myContext = {$implicit: ‘World’, localSk: ‘Svet’};模板中用let-绑定上下文, $implicit(implicit 隐式的)指默认值，也就是例如let-keyXX=”parameterXX”的语法在缺省=”parameterXX”的表达下的值
响应式解决方案npm install @angular/sdk注意该package大版本跟随Angular版本Angular CDK Layoutconstructor(private breakpointObserver: BreakpointObserver) &#123;    this.breakpointObserver.observe([Breakpoints.XSmall, Breakpoints.Small]).subscribe(result &#x3D;&gt; &#123;      if (result.matches) &#123;        &#x2F;&#x2F; max-width: 959px        this.windowWidth &#x3D; &#123; width: &#96;$&#123;this.slickWidth&#125;px&#96; &#125;;        this.interval &#x3D; 1;      &#125; else &#123;        this.windowWidth &#x3D; &#123; width: &#96;$&#123;this.slickWidth * 3&#125;px&#96; &#125;;        this.interval &#x3D; 3;      &#125;    &#125;);&#125;

