&lt;app-voter *ngFor&#x3D;&quot;let voter of voters&quot;      [name]&#x3D;&quot;voter&quot;      (voted)&#x3D;&quot;onVoted($event)&quot;&gt;&lt;&#x2F;app-voter&gt;
@Input()
@Input()可以带set、get属性

import &#123; Component, Input &#125; from &#39;@angular&#x2F;core&#39;;@Component(&#123;  selector: &#39;app-voter&#39;,  template: &#39;&lt;h3&gt;&quot;&#123;&#123;name&#125;&#125;&quot;&lt;&#x2F;h3&gt;&#39;&#125;)export class VoterComponent &#123;  private _name &#x3D; &#39;&#39;;  @Input()  set name(name: string) &#123;    this._name &#x3D; (name &amp;&amp; name.trim()) || &#39;&lt;no name set&gt;&#39;;  &#125;  get name(): string &#123; return this._name; &#125;&#125;
在set、get时进行格式化等操作。

ngOnChanges()生命周期钩子是专门用来监听@Input入参的，非传入参数不会触发ngOnChanges()方法

@Output()子组件发射事件@Output() voted &#x3D; new EventEmitter&lt;boolean&gt;();vote(agreed: boolean) &#123;    this.voted.emit(agreed);&#125;
模板标记子组件&lt;h3&gt;Countdown to Liftoff (via local variable)&lt;&#x2F;h3&gt;&lt;button (click)&#x3D;&quot;timer.start()&quot;&gt;Start&lt;&#x2F;button&gt;&lt;button (click)&#x3D;&quot;timer.stop()&quot;&gt;Stop&lt;&#x2F;button&gt;&lt;div class&#x3D;&quot;seconds&quot;&gt;&#123;&#123;timer.seconds&#125;&#125;&lt;&#x2F;div&gt;&lt;app-countdown-timer #timer&gt;&lt;&#x2F;app-countdown-timer&gt;
timer 作为父组件的变量，标记在子组件标签中，用以代表子组件，即可使父组件获取子组件的引用，进而可以调用子组件公用方法该方法有局限性在于，父组件-子组件的连接必须全部在父组件的模板中进行。父组件本身的代码对子组件没有访问权。
@ViewChild()@ViewChild(CountdownTimerComponent)private timerComponent: CountdownTimerComponent;
使用@ViewChild()装饰器将CountdownTimerComponent实例注入到本组件，记为私有变量timerComponent

特别注意被注入的组件只有在 Angular 显示了父组件视图之后才能访问下面的语法很关键
ngAfterViewInit() &#123;    &#x2F;&#x2F; wait a tick first to avoid one-time devMode    &#x2F;&#x2F; unidirectional-data-flow-violation error    setTimeout(() &#x3D;&gt;  this.timerComponent.init(), 0);  &#125;
父组件要及时调用子组件方法进行初始化，须实现AfterViewInit生命周期钩子，且用定时器异步操作。否则报异常
ExpressionChangedAfterItHasBeenCheckedError
引入第三者通信这类方法包括注入服务，借助相同父组件以及借助发布订阅可观察对象等，此处略。

注册响应式表单模块该模块定义了响应式表单涉及到的组件等类型或构造方法类定义在@angular/forms包中，会在组件中引用，那么为什么要注册模块？import &#123; ReactiveFormsModule &#125; from &#39;@angular&#x2F;forms&#39;;@NgModule(&#123;  imports: [    &#x2F;&#x2F; other imports ...    ReactiveFormsModule  ],&#125;)export class AppModule &#123; &#125;
FormControl响应式控件类，每个实例对应页面表单中的一个控件，在template中使用formControl=”name”绑定，在FormGroup中使用formControlName=”name”绑定。edit.component.ts:name &#x3D; new FormControl(&#39;QQstone&#39;)edit.component.html&lt;input type&#x3D;&quot;text&quot; [formControl]&#x3D;&quot;name&quot;&gt;&lt;p&gt;&#123;&#123;name.value&#125;&#125;&lt;&#x2F;p&gt;
FormGroup用于管理一组响应式控件，一个表单可以标记为一个Group，也可以分为多个Group（QQs尚为实践过）&lt;form #f&#x3D;&quot;ngForm&quot; *ngIf&#x3D;&quot;assetForm&quot; (ngSubmit)&#x3D;&quot;save()&quot; nz-form [formGroup]&#x3D;&quot;assetForm&quot;&gt;    &lt;nz-form-label nzSpan&#x3D;&quot;4&quot; nzRequired&gt;Asset Name&lt;&#x2F;nz-form-label&gt;    &lt;nz-form-control nzSpan&#x3D;&quot;8&quot;&gt;      &lt;input nz-input formControlName&#x3D;&quot;asset_name&quot; name&#x3D;&quot;name&quot; maxlength&#x3D;&quot;30&quot; placeholder&#x3D;&quot;Name&quot; required &#x2F;&gt;    &lt;&#x2F;nz-form-control&gt;    &lt;nz-form-label nzSpan&#x3D;&quot;4&quot; nzRequired&gt;Status&lt;&#x2F;nz-form-label&gt;    &lt;nz-form-control nzSpan&#x3D;&quot;8&quot;&gt;      &lt;nz-select formControlName&#x3D;&quot;status&quot; name&#x3D;&quot;status&quot; nzPlaceHolder&#x3D;&quot;Status&quot;         nzAllowClear required&gt;        &lt;nz-option *ngFor&#x3D;&quot;let item of enum.asset_status&quot; [nzLabel]&#x3D;&quot;item.text&quot; [nzValue]&#x3D;&quot;item.code&quot;&gt;        &lt;&#x2F;nz-option&gt;      &lt;&#x2F;nz-select&gt;    &lt;&#x2F;nz-form-control&gt;&lt;&#x2F;form&gt;
FormBuilder使用FormBuilder构造FormGroup,每个组件对应一个Array，Array第一个属性是控件初始value，其后是校验器，若存在多个校验器，则该属性为Array注入 private fb: FormBuilderprofileForm &#x3D; this.fb.group(&#123;    name:[&#39;&#39;, Validators.required],    status:[&#39;30&#39;]&#125;)

在你的应用中安装sdk向Azure Application Insight服务发送遥测数据，支持web客户端，web服务和后台服务等对应用性能影响小。非阻塞，单独线程

The instrumentation monitors your app and directs the telemetry data to an Azure Application Insights Resource using a unique GUID that we refer to as an Instrumentation Key. You can instrument not only the web service application, but also any background components, and the JavaScript in the web pages themselves. The application and its components can run anywhere - it doesn’t have to be hosted in Azure.  使用Guid作为Instrumentation Key(ikey)标识作为监视器的Azure Insights资源。 监测web服务应用或后台组件亦或页面js 这些应用或组件、命令不必托管在Azure中
创建Azure App Insights资源Azure Portal -&gt; Application Insights -&gt; Create
添加Javascript SDKnpm i --save @microsoft&#x2F;applicationinsights-web
使用ikey或连接字符串创建客户端instanceimport &#123; ApplicationInsights &#125; from &#39;@microsoft&#x2F;applicationinsights-web&#39;const appInsights &#x3D; new ApplicationInsights(&#123; config: &#123;  instrumentationKey: &#39;YOUR_INSTRUMENTATION_KEY_GOES_HERE&#39; &#x2F;* 使用ikey *&#x2F;  &#x2F;* 或使用 connectionString: &#39;YOUR_CONNECTION_STRING_GOES_HERE&#39; *&#x2F;  &#x2F;* ...Other Configuration Options... *&#x2F;&#125; &#125;);appInsights.loadAppInsights();appInsights.trackPageView(); &#x2F;&#x2F; Manually call trackPageView to establish the current user&#x2F;session&#x2F;pageviewReact Pluginnpm install @microsoft&#x2F;applicationinsights-react-jsnpm install @microsoft&#x2F;applicationinsights-web创建实例&#x2F;&#x2F; AppInsights.jsimport &#123; ApplicationInsights &#125; from &#39;@microsoft&#x2F;applicationinsights-web&#39;;import &#123; ReactPlugin &#125; from &#39;@microsoft&#x2F;applicationinsights-react-js&#39;;import &#123; createBrowserHistory &#125; from &#39;history&#39;;const browserHistory &#x3D; createBrowserHistory(&#123; basename: &#39;&#39; &#125;);const reactPlugin &#x3D; new ReactPlugin();const appInsights &#x3D; new ApplicationInsights(&#123;    config: &#123;        instrumentationKey: &#39;YOUR_INSTRUMENTATION_KEY_GOES_HERE&#39;,        extensions: [reactPlugin],        extensionConfig: &#123;          [reactPlugin.identifier]: &#123; history: browserHistory &#125;        &#125;    &#125;&#125;);appInsights.loadAppInsights();export &#123; reactPlugin, appInsights &#125;;在AppComponent使用Context.Provider 使所有子组件内可使用 useContext hook调用AppInsights实例import React from &quot;react&quot;;import &#123; AppInsightsContext &#125; from &quot;@microsoft&#x2F;applicationinsights-react-js&quot;;import &#123; reactPlugin &#125; from &quot;.&#x2F;AppInsights&quot;;const App &#x3D; () &#x3D;&gt; &#123;    return (        &lt;AppInsightsContext.Provider value&#x3D;&#123;reactPlugin&#125;&gt;            &#x2F;* your application here *&#x2F;        &lt;&#x2F;AppInsightsContext.