each middleware extension method is exposed on IApplicationBuilder through the Microsoft.AspNetCore.Builder namespace. 通过IApplicationBuilder接口方法引入中间件，IApplicationBuilder由Microsoft.AspNetCore.Builder命名空间提供

中间件的具体实现public class RequestIPMiddleware&#123;    private readonly RequestDelegate _next;    private readonly ILogger _logger;    public RequestIPMiddleware(RequestDelegate next, ILoggerFactory loggerFactory)    &#123;        _next &#x3D; next;        _logger &#x3D; loggerFactory.CreateLogger&lt;RequestIPMiddleware&gt;();    &#125;    public async Task Invoke(HttpContext context)    &#123;        _logger.LogInformation(&quot;User Ip: &quot; + context.Connection.RemoteIpAddress.ToString());        await _next.Invoke(context);    &#125;&#125;使用中间Startup.cspublic void Configure(IApplicationBuilder app, IHostingEnvironment env)&#123;    ....    app.UseRequestIp();&#125;

EntirtyFramework框架是一个轻量级的可扩展版本的流行实体框架数据访问技术,ORM工具(Object Relational Mapping 对象关系映射)

EF有三种使用场景，1. 从数据库生成Class(DB First)，2.由实体类生成数据库表结构(Code First)，3.  通过数据库可视化设计器设计数据库，同时生成实体类(Model First)。
实体类型class MyContext : DbContext&#123;    public DbSet&lt;Blog&gt; Blogs &#123; get; set; &#125;    protected override void OnModelCreating(ModelBuilder modelBuilder)    &#123;        modelBuilder.Entity&lt;Blog&gt;();    &#125;&#125;public class Blog&#123;    public int BlogId &#123; get; set; &#125;    public string Url &#123; get; set; &#125;    public List&lt;Post&gt; Posts &#123; get; set; &#125;&#125;&#x2F;&#x2F; 从模型中排除的类型[NotMapped]public class BlogMetadata&#123;    public DateTime LoadedFromDatabase &#123; get; set; &#125;&#125;

按照约定，每个实体类型将设置为映射到与公开实体的 DbSet 属性同名的数据库表。 如果给定实体不存在 DbSet，则使用类名称。或使用注解 [ Table(“tableName”) ]
实体属性public class Blog&#123;    public int BlogId &#123; get; set; &#125;    public string Url &#123; get; set; &#125;    &#x2F;&#x2F;从模型中排除的属性    [NotMapped]    public DateTime LoadedFromDatabase &#123; get; set; &#125;&#125;
列注解：

列名 [ Column(“blog_id”) ]
数据类型 [Column(TypeName = “varchar(200)”)]
校验  [ MaxLength(500) ] [ Required ]       


键主键protected override void OnModelCreating(ModelBuilder modelBuilder)&#123;    modelBuilder.Entity&lt;Blog&gt;()        .HasKey(b &#x3D;&gt; b.BlogId)        .HasName(&quot;PrimaryKey_BlogId&quot;);&#125;Alternative Keyclass MyContext : DbContext&#123;    public DbSet&lt;Blog&gt; Blogs &#123; get; set; &#125;    public DbSet&lt;Post&gt; Posts &#123; get; set; &#125;    protected override void OnModelCreating(ModelBuilder modelBuilder)    &#123;        modelBuilder.Entity&lt;Post&gt;()            .HasOne(p &#x3D;&gt; p.Blog)            .WithMany(b &#x3D;&gt; b.Posts)            .HasForeignKey(p &#x3D;&gt; p.BlogUrl)            .HasPrincipalKey(b &#x3D;&gt; b.Url);    &#125;&#125;
策略维护 多对多关系官网Doc

目前尚不支持多对多关系，没有实体类来表示联接表。 但是，您可以通过包含联接表的实体类并映射两个不同的一对多关系，来表示多对多关系。class MyContext : DbContext&#123;    public DbSet&lt;Post&gt; Posts &#123; get; set; &#125;    public DbSet&lt;Tag&gt; Tags &#123; get; set; &#125;    protected override void OnModelCreating(ModelBuilder modelBuilder)    &#123;        modelBuilder.Entity&lt;PostTag&gt;()            .HasKey(t &#x3D;&gt; new &#123; t.PostId, t.TagId &#125;);        modelBuilder.Entity&lt;PostTag&gt;()            .HasOne(pt &#x3D;&gt; pt.Post)            .WithMany(p &#x3D;&gt; p.PostTags)            .HasForeignKey(pt &#x3D;&gt; pt.PostId);        modelBuilder.Entity&lt;PostTag&gt;()            .HasOne(pt &#x3D;&gt; pt.Tag)            .WithMany(t &#x3D;&gt; t.PostTags)            .HasForeignKey(pt &#x3D;&gt; pt.TagId);    &#125;&#125;public class Post&#123;    public int PostId &#123; get; set; &#125;    public string Title &#123; get; set; &#125;    public string Content &#123; get; set; &#125;    public List&lt;PostTag&gt; PostTags &#123; get; set; &#125;&#125;public class Tag&#123;    public string TagId &#123; get; set; &#125;    public List&lt;PostTag&gt; PostTags &#123; get; set; &#125;&#125;public class PostTag&#123;    public int PostId &#123; get; set; &#125;    public Post Post &#123; get; set; &#125;    public string TagId &#123; get; set; &#125;    public Tag Tag &#123; get; set; &#125;&#125;
一对多&#x2F;&#x2F; 博客public class Blog&#123;    public int BlogId &#123; get; set; &#125;    public string Url &#123; get; set; &#125;    public List&lt;Post&gt; Posts &#123; get; set; &#125;&#125;&#x2F;&#x2F; 文章public class Post&#123;    public int PostId &#123; get; set; &#125;    public string Title &#123; get; set; &#125;    public string Content &#123; get; set; &#125;    public int BlogId &#123; get; set; &#125;    public Blog Blog &#123; get; set; &#125;&#125;

Post是依赖实体
Blog是主体实体
Blog.BlogId是主体键（在本例中为主密钥，而不是备用密钥）
Post.BlogId为外键
Post.Blog是一个引用导航属性
Blog.Posts是集合导航属性
Post.Blog是的反向导航属性 一对一public class Blog&#123;    public int BlogId &#123; get; set; &#125;    public string Url &#123; get; set; &#125;    public BlogImage BlogImage &#123; get; set; &#125;&#125;public class BlogImage&#123;    public int BlogImageId &#123; get; set; &#125;    public byte[] Image &#123; get; set; &#125;    public string Caption &#123; get; set; &#125;    public int BlogId &#123; get; set; &#125;    public Blog Blog &#123; get; set; &#125;&#125;
配置关系时HasForeignKey必须指定实体类型，这一点区别于上面的书写方式modelBuilder.Entity&lt;Blog&gt;()    .HasOne(b &#x3D;&gt; b.BlogImage)    .WithOne(i &#x3D;&gt; i.Blog)    .HasForeignKey&lt;BlogImage&gt;(b &#x3D;&gt; b.BlogForeignKey);
关联关系class MyContext : DbContext&#123;    public DbSet&lt;Blog&gt; Blogs &#123; get; set; &#125;    public DbSet&lt;Post&gt; Posts &#123; get; set; &#125;    protected override void OnModelCreating(ModelBuilder modelBuilder)    &#123;        modelBuilder.Entity&lt;Post&gt;()            .HasOne&lt;Blog&gt;()            .WithMany()            .HasForeignKey(p &#x3D;&gt; p.BlogId);    &#125;&#125;关联关系有Reqiuired和Optional之分，前者的情况下，对主体实体的删除会导致依赖实体被级联删除，而对于后者，默认不被配置为级联删除而将外键属性置为null
关联查询public async Task&lt;IActionResult&gt; Details(string code)&#123;    if (code &#x3D;&#x3D; null)    &#123;        return NotFound();    &#125;    &#x2F;&#x2F; Blog &lt;&gt;--- ReferenceMap ---&lt;&gt; Theme    var Blog &#x3D; await _context. Blogs                    .Include(blog &#x3D;&gt; blog.ReferenceMap)                    .ThenInclude(map &#x3D;&gt; map.Theme)                    .FirstOrDefaultAsync(m &#x3D;&gt; m.Code &#x3D;&#x3D; code);    if (Blog &#x3D;&#x3D; null)    &#123;        return NotFound();    &#125;    return View(Blog);&#125;
Inclulde 被称为 预先加载 eager load使用ThenInclude关联多个层次Include可以包含过滤, 如下取得曾发表带’敏感’词标题文章的所有博客，以及相应的文章var restrictBlogs &#x3D; _context.Blogs.Include(blog &#x3D;&gt; blog.Posts.Where(post &#x3D;&gt; post.Title.Contains(&quot;敏感&quot;))).ToList()



显式加载(explicit load)var blog &#x3D; _context.Blogs.Single(blog&#x3D;&gt;blog.Author&#x3D;&#x3D;&quot;QQs&quot;) &#x2F;&#x2F; 此处关联属性Posts为null...var posts &#x3D; _context.Entry(blog).Collection(blog &#x3D;&gt; blog.Posts).Query().Where(post &#x3D;&gt; post.Title.Contains(&quot;敏感&quot;)).ToList() &#x2F;&#x2F; 此时blog对象的Posts属性被填充（仅过滤结果）不返回结果posts可以直接Load_context.Entry(blog).Collection(blog &#x3D;&gt; blog.Posts).Load()QQs：私以为这与预先加载并无多大区别
